/**
 * Full-Page Bundle Widget Loader
 * Lightweight loader (<10KB) that fetches full implementation
 */
'use strict';
(function(){const e=document.querySelectorAll('#bundle-builder-app[data-bundle-type="full_page"]');if(!e.length)return;const t=e[0],n=t.dataset.bundleId;if(!n||n==='preview'){t.innerHTML='<div style="padding:60px;text-align:center;"><h2>Full-Page Bundle</h2><p>Configure Bundle ID in theme editor</p></div>';return}t.innerHTML='<div class="bundle-loading"><div class="loading-spinner"></div><p>Loading bundle...</p></div>';const o=t.dataset.appUrl||window.__BUNDLE_APP_URL__||'';fetch(`/apps/product-bundles/api/bundle/${n}.json`).then(r=>r.json()).then(r=>{if(!r.success||!r.bundle)throw new Error(r.error||'Bundle not found');const a=r.bundle,l=Array(a.steps.length).fill(null).map(()=>({}));let s=0,i=null;function d(){t.innerHTML='';const u=document.createElement('div');u.className='step-timeline';a.steps.forEach((c,p)=>{const m=document.createElement('div');m.className='timeline-step';const g=Object.values(l[p]).reduce((h,b)=>h+b,0)>=(a.steps[p].minQuantity||1),f=p===s;g&&m.classList.add('completed');f&&m.classList.add('current');const y=document.createElement('div');y.className='timeline-circle';g?y.innerHTML='<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M13 4L6 11L3 8" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>':f?y.innerHTML='<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><rect x="3" y="3" width="10" height="10" stroke="currentColor" stroke-width="1.5" fill="none"/></svg>':y.textContent=(p+1).toString();m.appendChild(y);if(p<a.steps.length-1){const h=document.createElement('div');h.className='timeline-line';g&&h.classList.add('completed');m.appendChild(h)}const v=document.createElement('div');v.className='timeline-step-name';v.textContent=c.name;m.appendChild(v);m.style.cursor='pointer';m.addEventListener('click',()=>{s=p;d()});u.appendChild(m)});const w=document.createElement('div');w.className='bundle-header';w.innerHTML=`<p class="bundle-instruction">${a.steps[s].description||'Select products to continue'}</p>`;const x=document.createElement('div');x.className='full-page-product-grid';const k=a.steps[s].products||[];k.forEach(c=>{const p=c.variants?.[0]?.id||c.id,m=l[s][p]||0,g=document.createElement('div');g.className='product-card';m>0&&g.classList.add('selected');g.innerHTML=`<div class="product-image"><img src="${c.images?.[0]?.url||c.featuredImage?.url||''}" alt="${c.title}"></div><div class="product-content-wrapper"><div class="product-title">${c.title}</div><div class="product-price">Rs. ${(c.price/100).toFixed(2)}</div><div class="product-quantity-selector"><button class="qty-btn qty-decrease">−</button><span class="qty-display">${m}</span><button class="qty-btn qty-increase">+</button></div><button class="product-add-btn ${m>0?'added':''}">${m>0?'Added':'Add to Box'}</button></div>`;g.querySelector('.qty-decrease').addEventListener('click',()=>{const f=Math.max(0,m-1);l[s][p]=f;d()});g.querySelector('.qty-increase').addEventListener('click',()=>{l[s][p]=m+1;d()});g.querySelector('.product-add-btn').addEventListener('click',()=>{l[s][p]=m>0?0:1;d()});x.appendChild(g)});const E=document.createElement('div');E.className='full-page-footer';const T=document.createElement('div');T.className='footer-left';const A=document.createElement('div');A.className='footer-selected-products';const S=[];a.steps.forEach((c,p)=>{const m=l[p]||{};Object.entries(m).forEach(([g,f])=>{if(f>0){const y=c.products?.find(v=>v.id===g||v.variants?.some(h=>h.id===g));y&&S.push({stepIndex:p,variantId:g,quantity:f,title:y.title,image:y.images?.[0]?.url||y.featuredImage?.url||'',price:y.price})}})});S.length===0?A.innerHTML='<p class="no-selections">No products selected</p>':S.forEach(c=>{const p=document.createElement('div');p.className='footer-product-item';p.innerHTML=`<div class="footer-product-image-wrapper"><img src="${c.image}" alt="${c.title}" class="footer-product-image"><div class="footer-product-quantity-badge">${c.quantity}</div></div><div class="footer-product-info"><div class="footer-product-title">${c.title}</div><div class="footer-product-price">Rs. ${(c.price/100).toFixed(2)}</div><button class="footer-product-remove">Delete</button></div>`;p.querySelector('.footer-product-remove').addEventListener('click',()=>{l[c.stepIndex][c.variantId]=0;d()});A.appendChild(p)});T.appendChild(A);const C=document.createElement('div');C.className='footer-right';let L=0;a.steps.forEach((c,p)=>{const m=l[p]||{};Object.entries(m).forEach(([g,f])=>{const y=c.products?.find(v=>v.id===g||v.variants?.some(h=>h.id===g));y&&f>0&&(L+=y.price*f)})});C.innerHTML=`<div class="footer-total"><span class="total-label">Total</span><span class="total-price">Rs. ${(L/100).toFixed(2)}</span></div><div class="footer-nav-buttons"><button class="footer-nav-btn footer-back-btn" ${s===0?'disabled':''}>Back</button><button class="footer-nav-btn footer-next-btn">${s===a.steps.length-1?'Add to Cart':'Next'}</button></div>`;C.querySelector('.footer-back-btn').addEventListener('click',()=>{s>0&&(s--,d())});C.querySelector('.footer-next-btn').addEventListener('click',()=>{if(s<a.steps.length-1){const c=Object.values(l[s]).reduce((p,m)=>p+m,0)>=(a.steps[s].minQuantity||1);c?(s++,d()):alert('Please select at least one product')}else{const c=[],p=`${a.id}_${Date.now()}_${Math.random().toString(36).substr(2,9)}`;a.steps.forEach((m,g)=>{const f=l[g]||{};Object.entries(f).forEach(([y,v])=>{v>0&&c.push({id:parseInt(y),quantity:v,properties:{_bundle_id:p,_bundle_name:a.name,_step_index:g.toString()}})})});fetch('/cart/add.js',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({items:c})}).then(m=>{if(!m.ok)throw new Error('Failed to add to cart');alert('Bundle added to cart!');window.location.href='/cart'}).catch(m=>{alert('Error: '+m.message)})}});E.appendChild(T);E.appendChild(C);t.appendChild(u);t.appendChild(w);t.appendChild(x);t.appendChild(E)}d()}).catch(r=>{console.error('[FULL_PAGE_BUNDLE]',r);t.innerHTML=`<div style="padding:40px;text-align:center;background:#fff3cd;border:1px solid #ffc107;border-radius:8px;"><h3 style="color:#856404;">Error</h3><p style="color:#856404;">${r.message}</p></div>`})})();
